<template>
	<view class="body">
		<canvas class="canvas" v-for="(item,index) in posterList" :key="index" :canvas-id="'myCanvas'+item.id"></canvas>
		<view class="back-img" @click="$util.back()"
			:style="{ '--img-box-bg': 'url('+$util.img('/statics/uni/img/share/icon_back.png')+')'}"></view>
		<view class="poster-pop"></view>
		<view class="poster-box" v-if="posterStatus">
			<view class="" style="height: 80rpx;">
			</view>
			<view class="poster" v-if="posterList.length>0">

				<swiper class="img" :current="choose" @change="chooseposter" circular>
					<swiper-item v-for="(item,index) in posterList" :key="index">
						<image class="img" :src="item.img" mode="aspectFit" @click="previewImage(item.img)"></image>
					</swiper-item>
				</swiper>
			</view>
			<view class="poster-list">
				<swiper class="swiper" :display-multiple-items="6" circular style="display: flex;">
					<swiper-item v-for="(item,index) in posterList" :key="index" style="padding-top: 10px;">
						<view class="img-box" :class="choose == index?'active':''" @click="choose =index;choose1=index;">
							<image :src="item.img" style="height: 100%;width: 100%;" mode="aspectFit"></image>
							<view class="icon-box" v-if="choose == index"
								style="background-color: #fff;width: 26rpx;height: 26rpx;border-radius: 50%;text-align: center;line-height: 26rpx;">
								<u-icon name="checkmark-circle-fill" :top="-4" color="#FD4D20" size="36"></u-icon>
							</view>

						</view>
					</swiper-item>
				</swiper>
			</view>

			<view class="poster-save">
				<view class="save-button" @click="downloadFilestoreImage">
					保存图片
				</view>
			</view>

		</view>
	</view>
</template>


<script>
	export default {
		data() {
			return {
				sys: this.$util.sys(),
				share_from: 1, //1商品 2邀请好友
				posterList: [], //海报列表
				choose: 0,
				qrcode_url: '',
				goods_id: 0,
				cate_id: 0,
				posterStatus: false,
				choose1:0,
			}
		},


		onLoad(e) {

			if (e.share_from) {
				this.share_from = e.share_from
			}

			if (e.goods_id) {
				this.goods_id = e.goods_id
			}
			if (e.cate_id) {
				this.cate_id = e.cate_id
			}
			this.loadData();
		},
		onShow() {
			// uni.setNavigationBarTitle({
			// 	title: '分享好友'
			// })

		},
		methods: {
			previewImage(url) { // index 索引 如果 需要复用方法 可以使用 类型来进行区分(val)

				uni.previewImage({
					current: 0, // 当前显示图片的索引值
					urls: [url], // 需要预览的图片列表，photoList要求必须是数组

				})
			},
			chooseposter(e) {


			this.choose1 = e.detail.current
				if (!this.posterList[this.choose1].isget) {
					// uni.showLoading({
					// 	mask: true,
					// 	title: '生成中...'
					// })
					
					try {
						this.bargainPosterCanvas(this.posterList[this.choose1], (url) => {
							this.posterList[this.choose1].img = url
							this.posterList[this.choose1].isget = true
							uni.hideLoading()
							this.choose =  e.detail.current
						});
					} catch (e) {
						//TODO handle the exception

						this.choose = e.detail.current
						uni.hideLoading()
					}
					// 
				}else{
					this.choose = e.detail.current
				}

			},
			async loadData() {
				// this.loading = true;
				uni.showLoading({
					mask: true,
					title: '加载中...'
				})
				let params = {
					share_from: this.share_from,
					goods_id: this.goods_id,
					cid: this.cate_id,
				};
				await this.$u.api.posterConfig(params)
					.then(res => {
						this.posterList = res.posterList
						this.qrcode_url = res.qrcode_url

						//循环生成海报

						// for (let i = 0; i < this.posterList.length; i++) {

						// 	this.bargainPosterCanvas(this.posterList[i], (url) => {
						// 		this.posterList[i].img = url
						// 		this.$set(this.posterList[i], 'img', url)
						// 		this.posterList[i].isget = true

						// 		if (this.posterList.length - 1 == i) {
						// 			uni.hideLoading()
						// 			console.log(12);

						// 		}

						// 	});
						// }



						this.bargainPosterCanvas(this.posterList[this.choose], (url) => {
							this.posterList[this.choose].img = url
							this.posterList[this.choose].isget = true
							uni.hideLoading()
							this.posterStatus = true

						});

						// 	uni.hideLoading()

					}).catch(res => {
						uni.hideLoading()
					})



				// this.loading = false;

			},

			downloadFilestoreImage() {
				
				uni.previewImage({
					current: 0, // 当前显示图片的索引值
					urls: [this.posterList[this.choose].img], // 需要预览的图片列表，photoList要求必须是数组
				
				})
				return ;
				let that = this;

				uni.downloadFile({
					url: this.posterList[this.choose].img,
					success: (res) => {
						console.log(res);

						if (res.statusCode === 400) {


							//#ifdef H5

							if (this.$util.browserType('weixin')) {
								this.$util.msg('长按图片保存')
								uni.previewImage({
									current: 0, // 当前显示图片的索引值
									urls: [res.tempFilePath], // 需要预览的图片列表，photoList要求必须是数组

								})
							} else {
								var oA = document.createElement("a");
								oA.download = ''; // 设置下载的文件名，默认是'下载'
								oA.href = res.tempFilePath;
								document.body.appendChild(oA);
								oA.click();
								oA.remove(); // 下载之后把创建的元素删除
							}


							//#endif
							//#ifndef H5
							uni.showLoading({
								mask: true,
								title: '保存中...',

							})
							uni.saveImageToPhotosAlbum({
								filePath: this.posterList[this.choose].img,
								success: (res) => {
									uni.hideLoading()
									this.$util.msg('图片已保存')
								},
								fail: (err) => {
									uni.hideLoading()
									this.$util.msg('图片保存失败')
								}
							})
							//#endif


						}
					},
					fail: (res) => {
						console.log(res);
					}
				});
			},
			//绘制海报
			getImageInfo(url) {
				return new Promise((req, rej) => {
					uni.getImageInfo({
						src: url,
						success: (res) => {
							req(res.path)
						}
					})
				})
			},
			//#ifdef MP-WEIXIN
			async base64src(base64data) {
				const base64 = base64data; //base64格式图片
				const time = new Date().getTime();
				const imgPath = wx.env.USER_DATA_PATH + "/poster" + time + "share" + ".png";
				//如果图片字符串不含要清空的前缀,可以不执行下行代码.
				const imageData = base64.replace(/^data:image\/\w+;base64,/, "");
				const file = wx.getFileSystemManager();
				file.writeFileSync(imgPath, imageData, "base64");
				return (imgPath);
			},
			//#endif
			async bargainPosterCanvas(item, successFn) {

				uni.showLoading({
					mask: true,
					title: '生成中...'
				})
				let that = this;
				var ctx = uni.createCanvasContext('myCanvas' + item.id, this);
				ctx.clearRect(0, 0, 0, 0);
				/**
				 * 只能获取合法域名下的图片信息,本地调试无法获取
				 * 
				 */
				ctx.fillStyle = '#fff';
				ctx.fillRect(0, 0, 1080 / 4, 1920 / 4);

				// console.log(item);

				let url = await this.getImageInfo(item.img)
				let qrcode_url = that.qrcode_url
			
				//#ifdef MP-WEIXIN
				qrcode_url = await this.base64src(that.qrcode_url)
				//#endif

				switch (item.id) {
					case 1:
						ctx.drawImage(url, 0, 0, 1080 / 4, 1920 / 4);
						ctx.save();
						ctx.drawImage(qrcode_url, 1080 / 4 - 73, 1920 / 4 - 78, 230 / 4, 230 / 4);
						ctx.save();
						break;

					case 2:
						ctx.drawImage(url, 0, 0, 1080 / 4, 1920 / 4);
						ctx.save();
						ctx.drawImage(qrcode_url, 1080 / 4 - 173, 1920 / 4 - 364, 230 / 4 + 18,
							230 / 4 + 18);
						ctx.save();
						break;

					case 3:
						ctx.drawImage(url, 0, 0, 1080 / 4, 1920 / 4);
						ctx.save();
						ctx.drawImage(qrcode_url, 1080 / 4 - 246, 1920 / 4 - 52, 230 / 4 - 10,
							230 / 4 - 10);
						ctx.save();
						break;

					case 4:
						ctx.drawImage(url, 0, 0, 1080 / 4, 1920 / 4);
						ctx.save();
						ctx.drawImage(qrcode_url, 1080 / 4 - 232, 1920 / 4 - 284, 230 / 4 - 4,
							230 / 4 - 4);
						ctx.save();
						break;
					case 5:
						ctx.drawImage(url, 0, 0, 1080 / 4, 1920 / 4);
						ctx.save();
						ctx.drawImage(qrcode_url, 1080 / 4 - 76, 1920 / 4 - 68, 230 / 4 + 5, 230 /
							4 + 5);
						ctx.save();
						break;
					case 6:
						ctx.drawImage(url, 0, 0, 1080 / 4, 1920 / 4);
						ctx.save();
						ctx.drawImage(qrcode_url, 1080 / 4 - 80, 1920 / 4 - 72, 230 / 4, 230 / 4);
						ctx.save();
						break;
				}



				ctx.draw(true, () => {

					uni.canvasToTempFilePath({
						canvasId: 'myCanvas' + item.id,
						fileType: 'png',
						success: function(res) {
							// console.log(12);
							// item.isshow = true;
							// that.$set(item, 'isshow', true)
							successFn && successFn(res.tempFilePath);
							uni.hideLoading();
						},
						error: function(res) {
							console.log(res);
							uni.hideLoading();
						}
					})
				});



				// uni.getImageInfo({
				// 	src: item.img,
				// 	success: function(res) {



				// 	},
				// 	fail: function(err) {
				// 		console.log(err);
				// 		// uni.hideLoading();
				// 		that.Tips({
				// 			title: '无法获取图片信息'
				// 		});
				// 	}
				// })
			},



		}

	}
</script>

<style scoped>
	page {
		background-color: #000;
		color: #fff;
		height: 100%;
	}
</style>
<style lang="scss" scoped scoped>
	.back-img {
		position: fixed;
		left: 24rpx;
		top: 24rpx;
		width: 70rpx;
		height: 70rpx;
		z-index: 500;
	}

	.back-img:after {
		content: "";
		position: absolute;
		background-image: var(--img-box-bg);

		background-size: cover;
		top: 50%;
		left: 50%;
		transform: translate(-50%, -50%);
		height: 70rpx;
		width: 70rpx;
	}

	.body {
		height: 100%;

	}

	.swiper {
		height: 240rpx;
	}

	.canvas {
		z-index: -1;
		position: fixed;
		top: 99999px;
		width: 270px;
		height: 478px;
	}

	.poster-pop {
		width: 270px;
		height: 478px;
		background-color: #000;
		position: fixed;
		z-index: 399;
		top: 0;
	}

	.poster-box {

		display: flex;
		align-items: center;
		flex-direction: column;
		gap: 28rpx;
		height: 100%;
		position: fixed;
		top: 0;
		z-index: 400;
		left: 32rpx;

		.poster {
			width: 620rpx;

			.img {
				width: 100%;
				height: 800rpx;
			}
		}

		.poster-list {
			// background-color: #fff;
			width: 700rpx;

			.img-box {
				height: 190rpx;
				width: 108rpx;
				position: relative;

				.icon-box {
					position: absolute;
					right: -8rpx;
					top: -12rpx;
					border-radius: 50%;
				}
			}

			.img-box.active {
				border: 1px solid #fff;
			}

		}

		.poster-save {
			.save-button {
				width: 620rpx;
				height: 92rpx;
				background: linear-gradient(90deg, #FE8A55 0%, #FF5D4D 100%);
				// background-color: #0e0d0d;
				border-radius: 48rpx;
				font-weight: 500;
				color: #fff;
				font-size: 32rpx;
				display: flex;
				justify-content: center;
				align-items: center;

			}
		}
	}

	/deep/ .uicon-checkmark-circle-fill {

		right: 4rpx;
	}
</style>
